import React, { useState, useEffect } from "react";
import FullPageLoader from "../components/FullPageLoader";
import RotatingTeeth from "../components/RotatingTeeth";
import Interactive3DTeeth from "../components/Interactive3DTeeth";

const FixMyTeeth = () => {
  // Add these if you want to support state, otherProblemText, and image uploads
  const [selectedState, setSelectedState] = useState('');
  const [otherProblemText, setOtherProblemText] = useState('');
  const [uploadedImages, setUploadedImages] = useState([]); // Array of { file, url }
  // State variables and handlers
  const [loading, setLoading] = useState(false);
  const [steps] = useState([
    { number: 1, title: 'Upload Photos', color: 'bg-blue-500' },
    { number: 2, title: 'Describe Problems', color: 'bg-yellow-500' },
    { number: 3, title: 'Select Location', color: 'bg-green-500' },
    { number: 4, title: 'Get Treatment Plan', color: 'bg-purple-500' }
  ]);
  const [showQuoteForm, setShowQuoteForm] = useState(false);
  const [dentalProblems] = useState([
    { id: 1, name: 'Toothache', icon: '🦷' },
    { id: 2, name: 'Cavity', icon: '🦷' },
    { id: 3, name: 'Gum Disease', icon: '🩸' },
    { id: 4, name: 'Broken Tooth', icon: '💥' },
    { id: 5, name: 'Stained Teeth', icon: '✨' }
  ]);
  const [selectedProblems, setSelectedProblems] = useState([]);
  const [form, setForm] = useState({ name: '', email: '' });
  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });
  const handleCaseSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    const formData = new FormData();
    formData.append("name", form.name);
    formData.append("email", form.email);
    formData.append("selectedProblems", JSON.stringify(selectedProblems));
    formData.append("selectedState", selectedState);
    if (otherProblemText) formData.append("otherProblemText", otherProblemText);
    // Append up to 10 images
    uploadedImages.slice(0, 10).forEach(img => formData.append("photo", img.file));

    try {
      const result = await submitFixMyTeethCase(formData);
      alert(result.message || "Submission complete!");
    } catch (err) {
      alert("Submission failed!");
    } finally {
      setLoading(false);
    }
  };
  const toggleProblem = (id) => {
    setSelectedProblems((prev) =>
      prev.includes(id) ? prev.filter((pid) => pid !== id) : [...prev, id]
    );
  };
  // Import the service
  // import { submitFixMyTeethCase } from "../services/fixMyTeethService";
  const submitFixMyTeethCase = async (formData) => {
    const service = await import("../services/fixMyTeethService");
    return service.submitFixMyTeethCase(formData);
  };

  if (loading) return <FullPageLoader />;

  return (
    <>
      <div className="min-h-screen py-4 sm:py-6 lg:py-8 px-3 sm:px-4 lg:px-6 transition-colors duration-300 bg-white">
        <div className="max-w-6xl mx-auto">
          {/* Header Section */}
          <div className="text-center mb-8 sm:mb-12">
            <h1 className="text-2xl sm:text-3xl md:text-4xl font-bold mb-3 sm:mb-4 px-2 text-[#2C73D2]">
              Fix My Teeth - Complete Dental Solution
            </h1>
            <p className="text-base sm:text-lg max-w-2xl mx-auto px-2 sm:px-4 text-gray-700">
              Get expert dental advice, personalized treatment plans, and comprehensive support for all your dental needs
            </p>
          </div>
          {/* Quick Treatment Plan Section */}
          <div className="rounded-2xl shadow-xl p-8 mb-12 theme-card bg-white">
            <div className="flex flex-col lg:flex-row items-center gap-8">
              {/* Left side - Hero content */}
              <div className="lg:w-1/2">
                <div className="mb-6">
                  <RotatingTeeth size={300} speed={3} />
                </div>
                <h2 className="text-2xl md:text-3xl font-bold text-gray-800 mb-4">
                  Get Your Dental Treatment Plan + Quote in 24 Hours - Only ₹149
                </h2>
                <p className="text-gray-600 mb-6 text-lg">
                  Select your dental problems, preferred location, and receive a detailed treatment plan and estimate from top clinics in India.
                </p>
              </div>
              {/* Right side - Steps */}
              <div className="lg:w-1/2">
                <div className="relative">
                  {steps.map((step, index) => (
                    <div key={step.number} className="relative">
                      <div className="flex items-center gap-4 mb-6">
                        <div className={`w-12 h-12 ${step.color} rounded-full flex items-center justify-center text-white font-bold text-lg relative z-10 shadow-lg`}>
                          {step.number}
                        </div>
                        <div className="flex-1">
                          <h3 className="font-semibold text-gray-800">{step.title}</h3>
                        </div>
                      </div>
                      {/* Connection Line */}
                      {index < steps.length - 1 && (
                        <div className="absolute left-6 top-12 w-0.5 h-6 bg-gradient-to-b from-gray-300 to-gray-400 transform -translate-x-0.5 z-0">
                          <div className="absolute top-1/2 left-1/2 w-2 h-2 bg-[#2C73D2] rounded-full transform -translate-x-1/2 -translate-y-1/2 animate-pulse"></div>
                        </div>
                      )}
                    </div>
                  ))}
                </div>
              </div>
            </div>
            {/* Treatment Plan Form */}
            {showQuoteForm && (
              <div className="mt-6 sm:mt-8 pt-6 sm:pt-8 border-t border-gray-200">
                <h3 className="text-xl sm:text-2xl font-bold text-gray-800 mb-4 sm:mb-6 px-2 text-center sm:text-left">
                  Tell Us What Dental Problems You're Facing
                </h3>
                {/* Dental Problems Grid */}
                <div className="mb-6 sm:mb-8">
                  <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-2 sm:gap-3 mb-4 sm:mb-6">
                    {dentalProblems.map((problem) => (
                      <React.Fragment key={problem.id}>
                        <button
                          onClick={() => toggleProblem(problem.id)}
                          className={`p-2 sm:p-3 rounded-lg border-2 transition-all duration-300 text-center hover:shadow-md active:scale-95 ${
                            selectedProblems.includes(problem.id)
                              ? 'border-[#2C73D2] bg-blue-50 text-[#2C73D2] shadow-md'
                              : 'border-gray-200 hover:border-[#2C73D2] hover:bg-gray-50'
                          }`}
                        >
                          <div className="text-lg sm:text-xl mb-1">{problem.icon}</div>
                          <div className="font-medium text-xs sm:text-sm leading-tight">{problem.name}</div>
                        </button>
                      </React.Fragment>
                    ))}
                  </div>
                  {selectedProblems.length > 0 && (
                    <div className="text-xs sm:text-sm text-gray-600 bg-blue-50 p-3 rounded-lg">
                      <span className="font-semibold">Selected: </span>
                      {selectedProblems.map(id => 
                        dentalProblems.find(p => p.id === id)?.name
                      ).join(', ')}
                    </div>
                  )}
                </div>
                {/* Contact Form */}
                <div className="grid md:grid-cols-2 gap-4 mb-6">
                {/* State selection */}
                <select
                  className="p-3 border-2 border-gray-200 rounded-lg focus:border-[#2C73D2] outline-none mb-4 w-full"
                  value={selectedState}
                  onChange={e => setSelectedState(e.target.value)}
                  required
                >
                  <option value="">Select State</option>
                  <option value="Delhi">Delhi</option>
                  <option value="Mumbai">Mumbai</option>
                  <option value="Bangalore">Bangalore</option>
                  <option value="Chennai">Chennai</option>
                  <option value="Kolkata">Kolkata</option>
                  {/* Add more states as needed */}
                </select>
                {/* Problem description */}
                <textarea
                  className="p-3 border-2 border-gray-200 rounded-lg focus:border-[#2C73D2] outline-none mb-4 w-full"
                  placeholder="Describe your dental problem (optional)"
                  value={otherProblemText}
                  onChange={e => setOtherProblemText(e.target.value)}
                  rows={3}
                />
                {/* Image upload */}
                <input
                  type="file"
                  accept="image/jpeg,image/png,image/jpg"
                  multiple
                  className="mb-4 w-full"
                  onChange={e => {
                    const files = Array.from(e.target.files).slice(0, 10);
                    setUploadedImages(files.map(file => ({ file, url: URL.createObjectURL(file) })));
                  }}
                />
                  <input
                    type="text"
                    placeholder="Name"
                    className="p-3 border-2 border-gray-200 rounded-lg focus:border-[#2C73D2] outline-none"
                    name="name"
                    value={form.name}
                    onChange={handleChange}
                  />
                  <input
                    type="email"
                    placeholder="Email"
                    className="p-3 border-2 border-gray-200 rounded-lg focus:border-[#2C73D2] outline-none"
                    name="email"
                    value={form.email}
                    onChange={handleChange}
                  />
                </div>
                <button
                  className="w-full bg-gradient-to-r from-[#2C73D2] to-[#F4A300] text-white py-4 rounded-lg font-semibold text-lg hover:from-blue-700 hover:to-yellow-500 transition-all duration-300"
                  onClick={handleCaseSubmit}
                  type="button"
                >
                  Get Treatment Plan - Pay ₹149
                </button>
              </div>
            )}
          </div>
        </div>
      </div>
    </>
  );
};

export default FixMyTeeth;
